import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterLink } from '@angular/router';
import { TaxReturn } from '../../core/models';

/** Filer dashboard: lists this filer's returns and starts a new one. */
@Component({
  selector: 'app-returns-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './returns-list.component.html',
  styleUrl: './returns-list.component.css',
})
export class ReturnsListComponent {
  loading = signal<boolean>(false);
  error = signal<string>('');

  // Mock data — service_agent clears these signals and wires them to ApiService.
  returns = signal<TaxReturn[]>([
    {
      id: 'r-2024',
      userId: 'me',
      year: 2024,
      filingStatus: 'single',
      currentStep: 'income',
      status: 'draft',
      updatedAt: '2026-03-14',
    },
    {
      id: 'r-2023',
      userId: 'me',
      year: 2023,
      filingStatus: 'married_joint',
      currentStep: 'review',
      status: 'complete',
      updatedAt: '2025-04-02',
    },
  ]);

  readonly stepLabels: Record<string, string> = {
    filing_status: 'Filing status',
    dependents: 'Dependents',
    income: 'Income',
    deductions: 'Deductions',
    review: 'Review',
  };

  readonly statusLabels: Record<string, string> = {
    single: 'Single',
    married_joint: 'Married filing jointly',
    married_separate: 'Married filing separately',
    head_of_household: 'Head of household',
  };

  constructor(private router: Router) {}

  newReturn(): void {
    const year = new Date().getFullYear() - 1;
    const id = 'r-' + year + '-' + this.returns().length;
    const created: TaxReturn = {
      id,
      userId: 'me',
      year,
      filingStatus: 'single',
      currentStep: 'filing_status',
      status: 'draft',
    };
    this.returns.update((rs) => [created, ...rs]);
    this.router.navigate(['/returns', id, 'wizard', 'filing-status']);
  }

  open(r: TaxReturn): void {
    this.router.navigate(['/returns', r.id, 'wizard']);
  }
}
